const encounterItems = $('Fetch Encounters').all().map(i => i.json);
const evalItems =$('Fetch Eval Results').all().map(i => i.json);

// GPT-4o list rates — approximate, verify against current OpenAI pricing page.
// Excludes Pinecone embedding tokens (tracked separately, not yet captured).
const RATE_PROMPT_PER_1M = 2.50;
const RATE_COMPLETION_PER_1M = 10.00;

const tiers = ['critical', 'urgent', 'low'];
const branch_split = {};
const latency_sum = {}, latency_count = {};
tiers.forEach(t => { branch_split[t] = { count: 0, pct: 0 }; latency_sum[t] = 0; latency_count[t] = 0; });

let esi_sum = 0, esi_count = 0;
let prompt_tokens_total = 0, completion_tokens_total = 0;

encounterItems.forEach(row => {
const branch = row.ai_branch;
if (branch && branch_split[branch]) branch_split[branch].count += 1;
if (row.esi_level != null) { esi_sum += Number(row.esi_level); esi_count += 1; }
if (branch && latency_sum.hasOwnProperty(branch) && row.latency_ms != null) {
latency_sum[branch] += Number(row.latency_ms);
latency_count[branch] += 1;
}
if (row.prompt_tokens != null) prompt_tokens_total += Number(row.prompt_tokens);
if (row.completion_tokens != null) completion_tokens_total += Number(row.completion_tokens);
});

const total_encounters = encounterItems.length;
tiers.forEach(t => { branch_split[t].pct = total_encounters > 0 ? (branch_split[t].count / total_encounters * 100) : 0; });

const avg_latency_ms = {};
tiers.forEach(t => { avg_latency_ms[t] = latency_count[t] > 0 ? Math.round(latency_sum[t] / latency_count[t]) : null; });

const avg_esi = esi_count > 0 ? (esi_sum / esi_count) : null;
const estimated_cost_usd = (prompt_tokens_total / 1e6 * RATE_PROMPT_PER_1M) + (completion_tokens_total / 1e6 * RATE_COMPLETION_PER_1M);

const runMap = {};
evalItems.forEach(row => {
const id = row.eval_run_id;
if (!runMap[id]) runMap[id] = { eval_run_id: id, total: 0, passed: 0, dates: [] };
runMap[id].total += 1;
if (row.overall_pass) runMap[id].passed += 1;
if (row.created_at) runMap[id].dates.push(row.created_at);
});

const pass_rate_trend = Object.values(runMap).map(r => ({
eval_run_id: r.eval_run_id,
total: r.total,
passed: r.passed,
pass_pct: r.total > 0 ? (r.passed / r.total * 100) : 0,
run_date: r.dates.sort()[0]?.slice(0, 10) || null
})).sort((a, b) => (a.run_date || '').localeCompare(b.run_date || ''));

return [{ json: {
total_encounters,
avg_esi,
branch_split,
avg_latency_ms,
token_cost: {
prompt_tokens: prompt_tokens_total,
completion_tokens: completion_tokens_total,
estimated_cost_usd: Math.round(estimated_cost_usd * 100) / 100
},
pass_rate_trend
} }];
